1	import { coerceSecretRef, normalizeSecretInputString } from "../../config/types.secrets.js";
2	import type { AuthProfileCredential } from "./types.js";
3	
4	export type AuthCredentialReasonCode =
5	  | "ok"
6	  | "missing_credential"
7	  | "invalid_expires"
8	  | "expired"
9	  | "unresolved_ref";
10	
11	export type TokenExpiryState = "missing" | "valid" | "expired" | "invalid_expires";
12	
13	export function resolveTokenExpiryState(expires: unknown, now = Date.now()): TokenExpiryState {
14	  if (expires === undefined) {
15	    return "missing";
16	  }
17	  if (typeof expires !== "number") {
18	    return "invalid_expires";
19	  }
20	  if (!Number.isFinite(expires) || expires <= 0) {
21	    return "invalid_expires";
22	  }
23	  return now >= expires ? "expired" : "valid";
24	}
25	
26	function hasConfiguredSecretRef(value: unknown): boolean {
27	  return coerceSecretRef(value) !== null;
28	}
29	
30	function hasConfiguredSecretString(value: unknown): boolean {
31	  return normalizeSecretInputString(value) !== undefined;
32	}
33	
34	export function evaluateStoredCredentialEligibility(params: {
35	  credential: AuthProfileCredential;
36	  now?: number;
37	}): { eligible: boolean; reasonCode: AuthCredentialReasonCode } {
38	  const now = params.now ?? Date.now();
39	  const credential = params.credential;
40	
41	  if (credential.type === "api_key") {
42	    const hasKey = hasConfiguredSecretString(credential.key);
43	    const hasKeyRef = hasConfiguredSecretRef(credential.keyRef);
44	    if (!hasKey && !hasKeyRef) {
45	      return { eligible: false, reasonCode: "missing_credential" };
46	    }
47	    return { eligible: true, reasonCode: "ok" };
48	  }
49	
50	  if (credential.type === "token") {
51	    const hasToken = hasConfiguredSecretString(credential.token);
52	    const hasTokenRef = hasConfiguredSecretRef(credential.tokenRef);
53	    if (!hasToken && !hasTokenRef) {
54	      return { eligible: false, reasonCode: "missing_credential" };
55	    }
56	
57	    const expiryState = resolveTokenExpiryState(credential.expires, now);
58	    if (expiryState === "invalid_expires") {
59	      return { eligible: false, reasonCode: "invalid_expires" };
60	    }
61	    if (expiryState === "expired") {
62	      return { eligible: false, reasonCode: "expired" };
63	    }
64	    return { eligible: true, reasonCode: "ok" };
65	  }
66	
67	  if (
68	    normalizeSecretInputString(credential.access) === undefined &&
69	    normalizeSecretInputString(credential.refresh) === undefined
70	  ) {
71	    return { eligible: false, reasonCode: "missing_credential" };
72	  }
73	  return { eligible: true, reasonCode: "ok" };
74	}
