47	const loadedAuthStoreCache = new Map<
48	  string,
49	  {
50	    authMtimeMs: number | null;
51	    stateMtimeMs: number | null;
52	    syncedAtMs: number;
53	    store: AuthProfileStore;
54	  }
55	>();
