87	function readAuthStoreMtimeMs(authPath: string): number | null {
88	  try {
89	    return fs.statSync(authPath).mtimeMs;
90	  } catch {
91	    return null;
92	  }
93	}
94	
95	function readCachedAuthProfileStore(params: {
96	  authPath: string;
97	  authMtimeMs: number | null;
98	  stateMtimeMs: number | null;
99	}): AuthProfileStore | null {
100	  const cached = loadedAuthStoreCache.get(params.authPath);
101	  if (
102	    !cached ||
103	    cached.authMtimeMs !== params.authMtimeMs ||
104	    cached.stateMtimeMs !== params.stateMtimeMs
105	  ) {
106	    return null;
107	  }
108	  if (Date.now() - cached.syncedAtMs >= EXTERNAL_CLI_SYNC_TTL_MS) {
109	    return null;
110	  }
111	  return cloneAuthProfileStore(cached.store);
112	}
113	
114	function writeCachedAuthProfileStore(params: {
115	  authPath: string;
116	  authMtimeMs: number | null;
117	  stateMtimeMs: number | null;
118	  store: AuthProfileStore;
119	}): void {
120	  loadedAuthStoreCache.set(params.authPath, {
121	    authMtimeMs: params.authMtimeMs,
122	    stateMtimeMs: params.stateMtimeMs,
123	    syncedAtMs: Date.now(),
124	    store: cloneAuthProfileStore(params.store),
125	  });
126	}
