128	export async function updateAuthProfileStoreWithLock(params: {
129	  agentDir?: string;
130	  updater: (store: AuthProfileStore) => boolean;
131	}): Promise<AuthProfileStore | null> {
132	  const authPath = resolveAuthStorePath(params.agentDir);
133	  ensureAuthStoreFile(authPath);
134	
135	  try {
136	    return await withFileLock(authPath, AUTH_STORE_LOCK_OPTIONS, async () => {
137	      // Locked writers must reload from disk, not from any runtime snapshot.
138	      // Otherwise a live gateway can overwrite fresher CLI/config-auth writes
139	      // with stale in-memory auth state during usage/cooldown updates.
140	      const store = loadAuthProfileStoreForAgent(params.agentDir);
141	      const shouldSave = params.updater(store);
142	      if (shouldSave) {
143	        saveAuthProfileStore(store, params.agentDir);
144	      }
145	      return store;
146	    });
147	  } catch {
148	    return null;
149	  }
150	}
