175	export function loadAuthProfileStore(): AuthProfileStore {
176	  const asStore = loadPersistedAuthProfileStore();
177	  if (asStore) {
178	    // Sync from external CLI tools on every load.
179	    syncExternalCliCredentialsTimed(asStore);
180	    return overlayExternalAuthProfiles(asStore);
181	  }
182	  const legacy = loadLegacyAuthProfileStore();
183	  if (legacy) {
184	    const store: AuthProfileStore = {
185	      version: AUTH_STORE_VERSION,
186	      profiles: {},
187	    };
188	    applyLegacyAuthStore(store, legacy);
189	    syncExternalCliCredentialsTimed(store);
190	    return overlayExternalAuthProfiles(store);
191	  }
192	
193	  const store: AuthProfileStore = { version: AUTH_STORE_VERSION, profiles: {} };
194	  syncExternalCliCredentialsTimed(store);
195	  return overlayExternalAuthProfiles(store);
196	}
