198	function loadAuthProfileStoreForAgent(
199	  agentDir?: string,
200	  options?: LoadAuthProfileStoreOptions,
201	): AuthProfileStore {
202	  const readOnly = options?.readOnly === true;
203	  const authPath = resolveAuthStorePath(agentDir);
204	  const statePath = resolveAuthStatePath(agentDir);
205	  const authMtimeMs = readAuthStoreMtimeMs(authPath);
206	  const stateMtimeMs = readAuthStoreMtimeMs(statePath);
207	  if (!readOnly) {
208	    const cached = readCachedAuthProfileStore({
209	      authPath,
210	      authMtimeMs,
211	      stateMtimeMs,
212	    });
213	    if (cached) {
214	      return cached;
215	    }
216	  }
217	  const asStore = loadPersistedAuthProfileStore(agentDir);
218	  if (asStore) {
219	    // Runtime secret activation must remain read-only:
220	    // sync external CLI credentials in-memory, but never persist while readOnly.
221	    if (shouldSyncExternalCliCredentials(options)) {
222	      syncExternalCliCredentialsTimed(asStore, { log: !readOnly });
223	    }
224	    if (!readOnly) {
225	      writeCachedAuthProfileStore({
226	        authPath,
227	        authMtimeMs: readAuthStoreMtimeMs(authPath),
228	        stateMtimeMs: readAuthStoreMtimeMs(statePath),
229	        store: asStore,
230	      });
231	    }
232	    return asStore;
233	  }
234	
235	  // Fallback: inherit auth-profiles from main agent if subagent has none
236	  if (agentDir && !readOnly) {
237	    const mainStore = loadPersistedAuthProfileStore();
238	    if (mainStore && Object.keys(mainStore.profiles).length > 0) {
239	      // Clone only secret-bearing profiles to subagent directory for auth inheritance.
240	      saveJsonFile(authPath, buildPersistedAuthProfileSecretsStore(mainStore));
241	      log.info("inherited auth-profiles from main agent", { agentDir });
242	      const inherited = { version: mainStore.version, profiles: { ...mainStore.profiles } };
243	      writeCachedAuthProfileStore({
244	        authPath,
245	        authMtimeMs: readAuthStoreMtimeMs(authPath),
246	        stateMtimeMs: readAuthStoreMtimeMs(statePath),
247	        store: inherited,
248	      });
249	      return inherited;
250	    }
251	  }
252	
253	  const legacy = loadLegacyAuthProfileStore(agentDir);
254	  const store: AuthProfileStore = {
255	    version: AUTH_STORE_VERSION,
256	    profiles: {},
257	  };
258	  if (legacy) {
259	    applyLegacyAuthStore(store, legacy);
260	  }
261	
262	  const mergedOAuth = mergeOAuthFileIntoStore(store);
263	  // Keep external CLI credentials visible in runtime even during read-only loads.
264	  if (shouldSyncExternalCliCredentials(options)) {
265	    syncExternalCliCredentialsTimed(store, { log: !readOnly });
266	  }
267	  const forceReadOnly = process.env.OPENCLAW_AUTH_STORE_READONLY === "1";
268	  const shouldWrite = !readOnly && !forceReadOnly && (legacy !== null || mergedOAuth);
269	  if (shouldWrite) {
270	    saveAuthProfileStore(store, agentDir);
271	  }
272	
273	  // PR #368: legacy auth.json could get re-migrated from other agent dirs,
274	  // overwriting fresh OAuth creds with stale tokens (fixes #363). Delete only
275	  // after we've successfully written auth-profiles.json.
276	  if (shouldWrite && legacy !== null) {
277	    const legacyPath = resolveLegacyAuthStorePath(agentDir);
278	    try {
279	      fs.unlinkSync(legacyPath);
280	    } catch (err) {
281	      if ((err as NodeJS.ErrnoException)?.code !== "ENOENT") {
282	        log.warn("failed to delete legacy auth.json after migration", {
283	          err,
284	          legacyPath,
285	        });
286	      }
287	    }
288	  }
289	
290	  if (!readOnly) {
291	    writeCachedAuthProfileStore({
292	      authPath,
293	      authMtimeMs: readAuthStoreMtimeMs(authPath),
294	      stateMtimeMs: readAuthStoreMtimeMs(statePath),
295	      store,
296	    });
297	  }
298	  return store;
299	}
300	
301	export function loadAuthProfileStoreForRuntime(
302	  agentDir?: string,
303	  options?: LoadAuthProfileStoreOptions,
304	): AuthProfileStore {
305	  const store = loadAuthProfileStoreForAgent(agentDir, options);
306	  const authPath = resolveAuthStorePath(agentDir);
307	  const mainAuthPath = resolveAuthStorePath();
308	  if (!agentDir || authPath === mainAuthPath) {
309	    return overlayExternalAuthProfiles(store, { agentDir });
310	  }
311	
312	  const mainStore = loadAuthProfileStoreForAgent(undefined, options);
313	  return overlayExternalAuthProfiles(mergeAuthProfileStores(mainStore, store), {
314	    agentDir,
315	  });
316	}
317	
318	export function loadAuthProfileStoreForSecretsRuntime(agentDir?: string): AuthProfileStore {
319	  return loadAuthProfileStoreForRuntime(agentDir, { readOnly: true, allowKeychainPrompt: false });
320	}
321	
322	export function ensureAuthProfileStore(
323	  agentDir?: string,
324	  options?: { allowKeychainPrompt?: boolean },
325	): AuthProfileStore {
326	  const runtimeStore = resolveRuntimeAuthProfileStore(agentDir);
327	  if (runtimeStore) {
328	    return overlayExternalAuthProfiles(runtimeStore, { agentDir });
329	  }
330	
331	  const store = loadAuthProfileStoreForAgent(agentDir, options);
332	  const authPath = resolveAuthStorePath(agentDir);
333	  const mainAuthPath = resolveAuthStorePath();
334	  if (!agentDir || authPath === mainAuthPath) {
335	    return overlayExternalAuthProfiles(store, { agentDir });
336	  }
337	
338	  const mainStore = loadAuthProfileStoreForAgent(undefined, options);
339	  const merged = mergeAuthProfileStores(mainStore, store);
340	
341	  return overlayExternalAuthProfiles(merged, { agentDir });
342	}
343	
344	export function ensureAuthProfileStoreForLocalUpdate(agentDir?: string): AuthProfileStore {
345	  const options: LoadAuthProfileStoreOptions = { syncExternalCli: false };
346	  const store = loadAuthProfileStoreForAgent(agentDir, options);
347	  const authPath = resolveAuthStorePath(agentDir);
348	  const mainAuthPath = resolveAuthStorePath();
349	  if (!agentDir || authPath === mainAuthPath) {
350	    return store;
351	  }
352	
353	  const mainStore = loadAuthProfileStoreForAgent(undefined, {
354	    readOnly: true,
355	    syncExternalCli: false,
356	  });
357	  return mergeAuthProfileStores(mainStore, store);
358	}
