361	
362	export function replaceRuntimeAuthProfileStoreSnapshots(
363	  entries: Array<{ agentDir?: string; store: AuthProfileStore }>,
364	): void {
365	  replaceRuntimeAuthProfileStoreSnapshotsImpl(entries);
366	}
367	
368	export function clearRuntimeAuthProfileStoreSnapshots(): void {
369	  clearRuntimeAuthProfileStoreSnapshotsImpl();
370	  loadedAuthStoreCache.clear();
371	}
372	
373	export function saveAuthProfileStore(
374	  store: AuthProfileStore,
375	  agentDir?: string,
376	  options?: SaveAuthProfileStoreOptions,
377	): void {
378	  const authPath = resolveAuthStorePath(agentDir);
379	  const statePath = resolveAuthStatePath(agentDir);
380	  const payload = buildPersistedAuthProfileSecretsStore(store, ({ profileId, credential }) => {
381	    if (credential.type !== "oauth") {
382	      return true;
383	    }
384	    if (options?.filterExternalAuthProfiles === false) {
385	      return true;
386	    }
387	    return shouldPersistExternalAuthProfile({
388	      store,
389	      profileId,
390	      credential,
391	      agentDir,
392	    });
393	  });
394	  saveJsonFile(authPath, payload);
395	  savePersistedAuthProfileState(store, agentDir);
396	  const runtimeStore = cloneAuthProfileStore(store);
397	  if (shouldSyncExternalCliCredentials(options)) {
398	    syncExternalCliCredentialsTimed(runtimeStore, { log: false });
399	  }
400	  writeCachedAuthProfileStore({
401	    authPath,
402	    authMtimeMs: readAuthStoreMtimeMs(authPath),
403	    stateMtimeMs: readAuthStoreMtimeMs(statePath),
404	    store: runtimeStore,
405	  });
406	  if (hasRuntimeAuthProfileStoreSnapshot(agentDir)) {
407	    setRuntimeAuthProfileStoreSnapshot(runtimeStore, agentDir);
408	  }
409	}
