1	import { formatErrorMessage } from "../infra/errors.js";
2	import { collectProviderApiKeys, isApiKeyRateLimitError } from "./live-auth-keys.js";
3	
4	type ApiKeyRetryParams = {
5	  apiKey: string;
6	  error: unknown;
7	  attempt: number;
8	};
9	
10	type ExecuteWithApiKeyRotationOptions<T> = {
11	  provider: string;
12	  apiKeys: string[];
13	  execute: (apiKey: string) => Promise<T>;
14	  shouldRetry?: (params: ApiKeyRetryParams & { message: string }) => boolean;
15	  onRetry?: (params: ApiKeyRetryParams & { message: string }) => void;
16	};
17	
18	function dedupeApiKeys(raw: string[]): string[] {
19	  const seen = new Set<string>();
20	  const keys: string[] = [];
21	  for (const value of raw) {
22	    const apiKey = value.trim();
23	    if (!apiKey || seen.has(apiKey)) {
24	      continue;
25	    }
26	    seen.add(apiKey);
27	    keys.push(apiKey);
28	  }
29	  return keys;
30	}
31	
32	export function collectProviderApiKeysForExecution(params: {
33	  provider: string;
34	  primaryApiKey?: string;
35	}): string[] {
36	  const { primaryApiKey, provider } = params;
37	  return dedupeApiKeys([primaryApiKey?.trim() ?? "", ...collectProviderApiKeys(provider)]);
38	}
39	
40	export async function executeWithApiKeyRotation<T>(
41	  params: ExecuteWithApiKeyRotationOptions<T>,
42	): Promise<T> {
43	  const keys = dedupeApiKeys(params.apiKeys);
44	  if (keys.length === 0) {
45	    throw new Error(`No API keys configured for provider "${params.provider}".`);
46	  }
47	
48	  let lastError: unknown;
49	  for (let attempt = 0; attempt < keys.length; attempt += 1) {
50	    const apiKey = keys[attempt];
51	    try {
52	      return await params.execute(apiKey);
53	    } catch (error) {
54	      lastError = error;
55	      const message = formatErrorMessage(error);
56	      const retryable = params.shouldRetry
57	        ? params.shouldRetry({ apiKey, error, attempt, message })
58	        : isApiKeyRateLimitError(message);
59	
60	      if (!retryable || attempt + 1 >= keys.length) {
61	        break;
62	      }
63	
64	      params.onRetry?.({ apiKey, error, attempt, message });
65	    }
66	  }
67	
68	  if (lastError === undefined) {
69	    throw new Error(`Failed to run API request for ${params.provider}.`);
70	  }
71	  throw lastError;
72	}
