53	export function formatRemainingShort(
54	  remainingMs?: number,
55	  opts?: {
56	    underMinuteLabel?: string;
57	  },
58	): string {
59	  if (remainingMs === undefined || Number.isNaN(remainingMs)) {
60	    return "unknown";
61	  }
62	  if (remainingMs <= 0) {
63	    return "0m";
64	  }
65	  const roundedMinutes = Math.round(remainingMs / 60_000);
66	  if (roundedMinutes < 1) {
67	    return opts?.underMinuteLabel ?? "1m";
68	  }
69	  const minutes = roundedMinutes;
70	  if (minutes < 60) {
71	    return `${minutes}m`;
72	  }
73	  const hours = Math.round(minutes / 60);
74	  if (hours < 48) {
75	    return `${hours}h`;
76	  }
77	  const days = Math.round(hours / 24);
78	  return `${days}d`;
79	}
80	
81	function resolveOAuthStatus(
82	  expiresAt: number | undefined,
83	  now: number,
84	  warnAfterMs: number,
85	): { status: AuthProfileHealthStatus; remainingMs?: number } {
86	  if (!expiresAt || !Number.isFinite(expiresAt) || expiresAt <= 0) {
87	    return { status: "missing" };
88	  }
89	  const remainingMs = expiresAt - now;
90	  if (remainingMs <= 0) {
91	    return { status: "expired", remainingMs };
92	  }
93	  if (remainingMs <= warnAfterMs) {
94	    return { status: "expiring", remainingMs };
95	  }
96	  return { status: "ok", remainingMs };
97	}
98	
99	function buildProfileHealth(params: {
100	  profileId: string;
101	  credential: AuthProfileCredential;
102	  store: AuthProfileStore;
103	  cfg?: OpenClawConfig;
104	  now: number;
105	  warnAfterMs: number;
106	}): AuthProfileHealth {
107	  const { profileId, credential, store, cfg, now, warnAfterMs } = params;
108	  const label = resolveAuthProfileDisplayLabel({ cfg, store, profileId });
109	  const source = resolveAuthProfileSource(profileId);
110	  const provider = normalizeProviderId(credential.provider);
111	
112	  if (credential.type === "api_key") {
113	    return {
114	      profileId,
115	      provider,
116	      type: "api_key",
117	      status: "static",
118	      source,
119	      label,
120	    };
121	  }
122	
123	  if (credential.type === "token") {
124	    const eligibility = evaluateStoredCredentialEligibility({
125	      credential,
126	      now,
127	    });
128	    if (!eligibility.eligible) {
129	      const status: AuthProfileHealthStatus =
130	        eligibility.reasonCode === "expired" ? "expired" : "missing";
131	      return {
132	        profileId,
133	        provider,
134	        type: "token",
135	        status,
136	        reasonCode: eligibility.reasonCode,
137	        source,
138	        label,
139	      };
140	    }
141	    const expiryState = resolveTokenExpiryState(credential.expires, now);
142	    const expiresAt = expiryState === "valid" ? credential.expires : undefined;
143	    if (!expiresAt) {
144	      return {
145	        profileId,
146	        provider,
147	        type: "token",
148	        status: "static",
149	        source,
150	        label,
151	      };
152	    }
153	    const { status, remainingMs } = resolveOAuthStatus(expiresAt, now, warnAfterMs);
154	    return {
155	      profileId,
156	      provider,
157	      type: "token",
158	      status,
159	      reasonCode: status === "expired" ? "expired" : undefined,
160	      expiresAt,
161	      remainingMs,
162	      source,
163	      label,
164	    };
165	  }
166	
167	  const hasRefreshToken = typeof credential.refresh === "string" && credential.refresh.length > 0;
168	  const { status: rawStatus, remainingMs } = resolveOAuthStatus(
169	    credential.expires,
170	    now,
171	    warnAfterMs,
172	  );
173	  // OAuth credentials with a valid refresh token auto-renew on first API call,
174	  // so don't warn about access token expiration.
175	  const status =
176	    hasRefreshToken && (rawStatus === "expired" || rawStatus === "expiring") ? "ok" : rawStatus;
177	  return {
178	    profileId,
179	    provider,
180	    type: "oauth",
181	    status,
182	    expiresAt: credential.expires,
183	    remainingMs,
184	    source,
185	    label,
186	  };
187	}
