189	export function buildAuthHealthSummary(params: {
190	  store: AuthProfileStore;
191	  cfg?: OpenClawConfig;
192	  warnAfterMs?: number;
193	  providers?: string[];
194	}): AuthHealthSummary {
195	  const now = Date.now();
196	  const warnAfterMs = params.warnAfterMs ?? DEFAULT_OAUTH_WARN_MS;
197	  const providerFilter = params.providers
198	    ? new Set(params.providers.map((p) => normalizeProviderId(p)).filter(Boolean))
199	    : null;
200	
201	  const profiles = Object.entries(params.store.profiles)
202	    .filter(([_, cred]) =>
203	      providerFilter ? providerFilter.has(normalizeProviderId(cred.provider)) : true,
204	    )
205	    .map(([profileId, credential]) =>
206	      buildProfileHealth({
207	        profileId,
208	        credential,
209	        store: params.store,
210	        cfg: params.cfg,
211	        now,
212	        warnAfterMs,
213	      }),
214	    )
215	    .toSorted((a, b) => {
216	      if (a.provider !== b.provider) {
217	        return a.provider.localeCompare(b.provider);
218	      }
219	      return a.profileId.localeCompare(b.profileId);
220	    });
221	
222	  const providersMap = new Map<string, AuthProviderHealth>();
223	  for (const profile of profiles) {
224	    const existing = providersMap.get(profile.provider);
225	    if (!existing) {
226	      providersMap.set(profile.provider, {
227	        provider: profile.provider,
228	        status: "missing",
229	        profiles: [profile],
230	      });
231	    } else {
232	      existing.profiles.push(profile);
233	    }
234	  }
235	
236	  if (providerFilter) {
237	    for (const provider of providerFilter) {
238	      if (!providersMap.has(provider)) {
239	        providersMap.set(provider, {
240	          provider,
241	          status: "missing",
242	          profiles: [],
243	        });
244	      }
245	    }
246	  }
247	
248	  for (const provider of providersMap.values()) {
249	    if (provider.profiles.length === 0) {
250	      provider.status = "missing";
251	      continue;
252	    }
253	
254	    const oauthProfiles = provider.profiles.filter((p) => p.type === "oauth");
255	    const tokenProfiles = provider.profiles.filter((p) => p.type === "token");
256	    const apiKeyProfiles = provider.profiles.filter((p) => p.type === "api_key");
257	
258	    const expirable = [...oauthProfiles, ...tokenProfiles];
259	    if (expirable.length === 0) {
260	      provider.status = apiKeyProfiles.length > 0 ? "static" : "missing";
261	      continue;
262	    }
263	
264	    const expiryCandidates = expirable
265	      .map((p) => p.expiresAt)
266	      .filter((v): v is number => typeof v === "number" && Number.isFinite(v));
267	    if (expiryCandidates.length > 0) {
268	      provider.expiresAt = Math.min(...expiryCandidates);
269	      provider.remainingMs = provider.expiresAt - now;
270	    }
271	
272	    const statuses = new Set(expirable.map((p) => p.status));
273	    if (statuses.has("expired") || statuses.has("missing")) {
274	      provider.status = "expired";
275	    } else if (statuses.has("expiring")) {
276	      provider.status = "expiring";
277	    } else {
278	      provider.status = "ok";
279	    }
280	  }
281	
282	  const providers = Array.from(providersMap.values()).toSorted((a, b) =>
283	    a.provider.localeCompare(b.provider),
284	  );
285	
286	  return { now, warnAfterMs, profiles, providers };
287	}
