25	function normalizeSecretBackedField(params: {
26	  entry: Record<string, unknown>;
27	  valueField: "key" | "token";
28	  refField: "keyRef" | "tokenRef";
29	}): void {
30	  const value = params.entry[params.valueField];
31	  if (value == null || typeof value === "string") {
32	    return;
33	  }
34	  const ref = coerceSecretRef(value);
35	  if (ref && !coerceSecretRef(params.entry[params.refField])) {
36	    params.entry[params.refField] = ref;
37	  }
38	  delete params.entry[params.valueField];
39	}
