41	function normalizeRawCredentialEntry(raw: Record<string, unknown>): Partial<AuthProfileCredential> {
42	  const entry = { ...raw } as Record<string, unknown>;
43	  if (!("type" in entry) && typeof entry["mode"] === "string") {
44	    entry["type"] = entry["mode"];
45	  }
46	  if (!("key" in entry) && typeof entry["apiKey"] === "string") {
47	    entry["key"] = entry["apiKey"];
48	  }
49	  normalizeSecretBackedField({ entry, valueField: "key", refField: "keyRef" });
50	  normalizeSecretBackedField({ entry, valueField: "token", refField: "tokenRef" });
51	  return entry as Partial<AuthProfileCredential>;
52	}
53	
54	function parseCredentialEntry(
55	  raw: unknown,
56	  fallbackProvider?: string,
57	): { ok: true; credential: AuthProfileCredential } | { ok: false; reason: CredentialRejectReason } {
58	  if (!raw || typeof raw !== "object") {
59	    return { ok: false, reason: "non_object" };
60	  }
61	  const typed = normalizeRawCredentialEntry(raw as Record<string, unknown>);
62	  if (!AUTH_PROFILE_TYPES.has(typed.type as AuthProfileCredential["type"])) {
63	    return { ok: false, reason: "invalid_type" };
64	  }
65	  const provider = typed.provider ?? fallbackProvider;
66	  if (typeof provider !== "string" || provider.trim().length === 0) {
67	    return { ok: false, reason: "missing_provider" };
68	  }
69	  return {
70	    ok: true,
71	    credential: {
72	      ...typed,
73	      provider,
74	    } as AuthProfileCredential,
75	  };
76	}
