78	function warnRejectedCredentialEntries(source: string, rejected: RejectedCredentialEntry[]): void {
79	  if (rejected.length === 0) {
80	    return;
81	  }
82	  const reasons = rejected.reduce(
83	    (acc, current) => {
84	      acc[current.reason] = (acc[current.reason] ?? 0) + 1;
85	      return acc;
86	    },
87	    {} as Partial<Record<CredentialRejectReason, number>>,
88	  );
89	  log.warn("ignored invalid auth profile entries during store load", {
90	    source,
91	    dropped: rejected.length,
92	    reasons,
93	    keys: rejected.slice(0, 10).map((entry) => entry.key),
94	  });
95	}
