97	export function coerceLegacyAuthStore(raw: unknown): LegacyAuthStore | null {
98	  if (!raw || typeof raw !== "object") {
99	    return null;
100	  }

100	  }
101	  const record = raw as Record<string, unknown>;
102	  if ("profiles" in record) {
103	    return null;
104	  }
105	  const entries: LegacyAuthStore = {};
106	  const rejected: RejectedCredentialEntry[] = [];
107	  for (const [key, value] of Object.entries(record)) {
108	    const parsed = parseCredentialEntry(value, key);
109	    if (!parsed.ok) {
110	      rejected.push({ key, reason: parsed.reason });
111	      continue;
112	    }
113	    entries[key] = parsed.credential;
114	  }
115	  warnRejectedCredentialEntries("auth.json", rejected);
116	  return Object.keys(entries).length > 0 ? entries : null;
