146	function mergeRecord<T>(
147	  base?: Record<string, T>,
148	  override?: Record<string, T>,
149	): Record<string, T> | undefined {
150	  if (!base && !override) {
151	    return undefined;
152	  }
153	  if (!base) {
154	    return { ...override };
155	  }
156	  if (!override) {
157	    return { ...base };
158	  }
159	  return { ...base, ...override };
160	}
