162	export function mergeAuthProfileStores(
163	  base: AuthProfileStore,
164	  override: AuthProfileStore,
165	): AuthProfileStore {
166	  if (
167	    Object.keys(override.profiles).length === 0 &&
168	    !override.order &&
169	    !override.lastGood &&
170	    !override.usageStats
171	  ) {
172	    return base;
173	  }
174	  return {
175	    version: Math.max(base.version, override.version ?? base.version),
176	    profiles: { ...base.profiles, ...override.profiles },
177	    order: mergeRecord(base.order, override.order),
178	    lastGood: mergeRecord(base.lastGood, override.lastGood),
179	    usageStats: mergeRecord(base.usageStats, override.usageStats),
180	  };
181	}
