183	export function buildPersistedAuthProfileSecretsStore(
184	  store: AuthProfileStore,
185	  shouldPersistProfile?: (params: {
186	    profileId: string;
187	    credential: AuthProfileCredential;
188	  }) => boolean,
189	): AuthProfileSecretsStore {
190	  const profiles = Object.fromEntries(
191	    Object.entries(store.profiles).flatMap(([profileId, credential]) => {
192	      if (shouldPersistProfile && !shouldPersistProfile({ profileId, credential })) {
193	        return [];
194	      }
195	      if (credential.type === "api_key" && credential.keyRef && credential.key !== undefined) {
196	        const sanitized = { ...credential } as Record<string, unknown>;
197	        delete sanitized.key;
198	        return [[profileId, sanitized]];
199	      }
200	      if (credential.type === "token" && credential.tokenRef && credential.token !== undefined) {
201	        const sanitized = { ...credential } as Record<string, unknown>;
202	        delete sanitized.token;
203	        return [[profileId, sanitized]];
204	      }
205	      return [[profileId, credential]];
206	    }),
207	  ) as AuthProfileSecretsStore["profiles"];
208	
209	  return {
210	    version: AUTH_STORE_VERSION,
211	    profiles,
212	  };
213	}
