234	        ...(cred.email ? { email: cred.email } : {}),
235	      };
236	      continue;
237	    }
238	    store.profiles[profileId] = {
239	      type: "oauth",
240	      provider: credentialProvider,
241	      access: cred.access,
242	      refresh: cred.refresh,
243	      expires: cred.expires,
244	      ...(cred.enterpriseUrl ? { enterpriseUrl: cred.enterpriseUrl } : {}),
245	      ...(cred.projectId ? { projectId: cred.projectId } : {}),
246	      ...(cred.accountId ? { accountId: cred.accountId } : {}),
247	      ...(cred.email ? { email: cred.email } : {}),
