253	export function mergeOAuthFileIntoStore(store: AuthProfileStore): boolean {
254	  const oauthPath = resolveOAuthPath();
255	  const oauthRaw = loadJsonFile(oauthPath);
256	  if (!oauthRaw || typeof oauthRaw !== "object") {
257	    return false;
258	  }
259	  const oauthEntries = oauthRaw as Record<string, OAuthCredentials>;
260	  let mutated = false;
261	  for (const [provider, creds] of Object.entries(oauthEntries)) {
262	    if (!creds || typeof creds !== "object") {
263	      continue;
264	    }
265	    const profileId = `${provider}:default`;
266	    if (store.profiles[profileId]) {
267	      continue;
268	    }
269	    store.profiles[profileId] = {
270	      type: "oauth",
271	      provider,
272	      ...creds,
273	    };
274	    mutated = true;
275	  }
276	  return mutated;
277	}
