11	  }
12	  const normalized = Object.entries(raw as Record<string, unknown>).reduce(
13	    (acc, [provider, value]) => {
14	      if (!Array.isArray(value)) {
15	        return acc;
16	      }
17	      const list = value.map((entry) => normalizeOptionalString(entry) ?? "").filter(Boolean);
18	      if (list.length > 0) {
19	        acc[provider] = list;
20	      }
21	      return acc;
22	    },
23	    {} as Record<string, string[]>,
24	  );
25	  return Object.keys(normalized).length > 0 ? normalized : undefined;
26	}
