30	    return {};
31	  }
32	  const record = raw as Record<string, unknown>;
33	  return {
34	    order: normalizeAuthProfileOrder(record.order),
35	    lastGood:
36	      record.lastGood && typeof record.lastGood === "object"
37	        ? (record.lastGood as Record<string, string>)
38	        : undefined,
39	    usageStats:
40	      record.usageStats && typeof record.usageStats === "object"
41	        ? (record.usageStats as Record<string, ProfileUsageStats>)
