46	export function mergeAuthProfileState(
47	  base: AuthProfileState,
48	  override: AuthProfileState,
49	): AuthProfileState {
50	  const mergeRecord = <T>(left?: Record<string, T>, right?: Record<string, T>) => {
51	    if (!left && !right) {
52	      return undefined;
53	    }
54	    if (!left) {
55	      return { ...right };
56	    }
57	    if (!right) {
58	      return { ...left };
59	    }
60	    return { ...left, ...right };
61	  };
62	
63	  return {
64	    order: mergeRecord(base.order, override.order),
65	    lastGood: mergeRecord(base.lastGood, override.lastGood),
66	    usageStats: mergeRecord(base.usageStats, override.usageStats),
67	  };
68	}
