74	export function buildPersistedAuthProfileState(
75	  store: AuthProfileState,
76	): AuthProfileStateStore | null {
77	  const state = coerceAuthProfileState(store);
78	  if (!state.order && !state.lastGood && !state.usageStats) {
79	    return null;
80	  }
81	  return {
82	    version: AUTH_STORE_VERSION,
83	    ...(state.order ? { order: state.order } : {}),
84	    ...(state.lastGood ? { lastGood: state.lastGood } : {}),
85	    ...(state.usageStats ? { usageStats: state.usageStats } : {}),
86	  };
87	}
