89	export function savePersistedAuthProfileState(
90	  store: AuthProfileState,
91	  agentDir?: string,
92	): AuthProfileStateStore | null {
93	  const payload = buildPersistedAuthProfileState(store);
94	  const statePath = resolveAuthStatePath(agentDir);
95	  if (!payload) {
96	    try {
97	      fs.unlinkSync(statePath);
98	    } catch (error) {
99	      if ((error as NodeJS.ErrnoException)?.code !== "ENOENT") {
100	        throw error;
101	      }
102	    }
103	    return null;
104	  }
105	  saveJsonFile(statePath, payload);
106	  return payload;
107	}
