566	    authPermanentBackoffMinutes: 10,
567	    authPermanentMaxMinutes: 60,
568	    failureWindowHours: 24,
569	  } as const;
570	
571	  const resolvePositiveNumber = (value: unknown, fallback: number) =>
572	    typeof value === "number" && Number.isFinite(value) && value > 0 ? value : fallback;
573	
574	  const cooldowns = params.cfg?.auth?.cooldowns;
575	  const billingOverride = (() => {
576	    const map = cooldowns?.billingBackoffHoursByProvider;
577	    if (!map) {
578	      return undefined;
579	    }
580	    for (const [key, value] of Object.entries(map)) {
581	      if (normalizeProviderId(key) === params.providerId) {
582	        return value;
583	      }
584	    }
585	    return undefined;
586	  })();
587	
588	  const billingBackoffHours = resolvePositiveNumber(
589	    billingOverride ?? cooldowns?.billingBackoffHours,
590	    defaults.billingBackoffHours,
591	  );
592	  const billingMaxHours = resolvePositiveNumber(
593	    cooldowns?.billingMaxHours,
594	    defaults.billingMaxHours,
595	  );
596	  const authPermanentBackoffMinutes = resolvePositiveNumber(
597	    cooldowns?.authPermanentBackoffMinutes,
598	    defaults.authPermanentBackoffMinutes,
599	  );
600	  const authPermanentMaxMinutes = resolvePositiveNumber(
601	    cooldowns?.authPermanentMaxMinutes,
602	    defaults.authPermanentMaxMinutes,
603	  );
604	  const failureWindowHours = resolvePositiveNumber(
605	    cooldowns?.failureWindowHours,
606	    defaults.failureWindowHours,
607	  );
