609	  return {
610	    billingBackoffMs: billingBackoffHours * 60 * 60 * 1000,
611	    billingMaxMs: billingMaxHours * 60 * 60 * 1000,
612	    authPermanentBackoffMs: authPermanentBackoffMinutes * 60 * 1000,
613	    authPermanentMaxMs: authPermanentMaxMinutes * 60 * 1000,
614	    failureWindowMs: failureWindowHours * 60 * 60 * 1000,
